My test script:

```
import math

UNITS = {"B": -2,
         "KB": -1,
         "MB": 0,
         "GB": 1,
         "TB": 2}

def convert_mb(kb, unit):
    assert unit in UNITS, ("%s not a valid unit, valid units are %s."
                           % (unit, list(UNITS.keys())))
    return int(float(kb) // float(math.pow(1024, UNITS[unit])))

def convert_mb2(kb, unit):
    assert unit in UNITS, ("%s not a valid unit, valid units are %s."
                           % (unit, list(UNITS.keys())))
    return float(kb) / float(math.pow(1024, UNITS[unit]))

def convert_mb3(kb, unit):
    assert unit in UNITS, ("%s not a valid unit, valid units are %s."
                           % (unit, list(UNITS.keys())))
    return kb / math.pow(1024, UNITS[unit])

for i in (0, 0.1, 0.5, 0.9, 1, 7, 10, 100, 1000):
    for unit in UNITS.keys():
        print(convert_mb(float(i) * 1024, unit))
        print(convert_mb2(float(i) * 1024, unit))
        print(convert_mb3(float(i) * 1024, unit))
        print(f'={i}={unit}=')
```

